Code.Terraform:
```hcl
# 将 SNS 主题策略限制为账户（非公开）
resource "aws_sns_topic_policy" "<example_resource_name>" {
  arn    = "<TOPIC_ARN>"
  policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Action    = "sns:Publish"
      Resource  = "<TOPIC_ARN>"
      Principal = { AWS = "arn:aws:iam::<ACCOUNT_ID>:root" } # 关键：将主体限制为该账户以移除公共访问权限
    }]
  })
}
```
